import { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const ScoreBar = ({ score }) => {
  const color = score >= 70 ? '#10b981' : score >= 40 ? '#f59e0b' : '#ef4444';
  return (
    <div className="flex items-center gap-2">
      <div style={{ background: '#0a0d1a', width: 80, height: 5, borderRadius: 3 }}>
        <div style={{ background: color, width: `${score}%`, height: '100%', borderRadius: 3 }} />
      </div>
      <span style={{ color }} className="text-xs font-bold">{score}</span>
    </div>
  );
};

export default function AdminDashboard() {
  const [projects, setProjects] = useState([]);
  const [stats, setStats] = useState(null);
  const [filter, setFilter] = useState('pending');
  const [loading, setLoading] = useState(true);
  const [actionNote, setActionNote] = useState('');
  const [actionTarget, setActionTarget] = useState(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const [deletingId, setDeletingId] = useState(null);

  useEffect(() => {
    fetchStats();
    fetchProjects();
  }, [filter]);

  const fetchStats = () => {
    axios.get('/api/admin/stats').then(r => setStats(r.data)).catch(console.error);
  };

  const fetchProjects = () => {
    setLoading(true);
    axios.get(`/api/admin/projects?status=${filter}`)
      .then(r => setProjects(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const handleDecision = async (id, decision) => {
    try {
      await axios.patch(`/api/admin/projects/${id}/${decision}`, { adminNote: actionNote });
      toast.success(`Project ${decision}d successfully`);
      setActionTarget(null);
      setActionNote('');
      fetchProjects();
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Action failed');
    }
  };

  const handleDelete = async (id) => {
    setDeletingId(id);
    try {
      await axios.delete(`/api/admin/projects/${id}`);
      setProjects(prev => prev.filter(p => p._id !== id));
      setConfirmDeleteId(null);
      toast.success('Project deleted successfully.');
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete project.');
    } finally {
      setDeletingId(null);
    }
  };

  const statsList = stats ? [
    { label: 'Total Projects', value: stats.totalProjects, color: '#00d4aa' },
    { label: 'Pending Review', value: stats.pendingProjects, color: '#f59e0b' },
    { label: 'Approved', value: stats.approvedProjects, color: '#10b981' },
    { label: 'Rejected', value: stats.rejectedProjects, color: '#ef4444' },
    { label: 'Total Users', value: stats.totalUsers, color: '#8b5cf6' },
    { label: 'Total Funded', value: `$${(stats.totalFunding || 0).toLocaleString()}`, color: '#00d4aa' },
  ] : [];

  return (
    <div style={{ background: '#0a0d1a', minHeight: '100vh' }} className="px-6 py-10">
      <div className="max-w-6xl mx-auto">
        <div className="mb-10">
          <div className="flex items-center gap-2 mb-2">
            <span style={{ color: '#f59e0b' }}>⚙</span>
            <span className="text-gray-400 text-sm uppercase tracking-widest">Admin Panel</span>
          </div>
          <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold">BackerSphere X</h1>
        </div>

        {/* Stats grid */}
        {stats && (
          <div className="grid grid-cols-6 gap-3 mb-10">
            {statsList.map(s => (
              <div key={s.label} style={{ background: '#111827', border: '1px solid #1f2937' }}
                   className="p-4 rounded-xl text-center">
                <div style={{ color: s.color, fontFamily: 'Syne, sans-serif' }} className="text-2xl font-black">{s.value}</div>
                <div className="text-gray-500 text-xs mt-1">{s.label}</div>
              </div>
            ))}
          </div>
        )}

        {/* Filter tabs */}
        <div className="flex gap-2 mb-6">
          {['pending', 'approved', 'rejected', 'all'].map(f => (
            <button key={f} onClick={() => setFilter(f)}
              style={{
                background: filter === f ? '#00d4aa' : '#111827',
                color: filter === f ? '#0a0d1a' : '#9ca3af',
                border: filter === f ? 'none' : '1px solid #1f2937'
              }}
              className="px-4 py-2 rounded-lg text-sm font-medium capitalize transition-all">
              {f}
            </button>
          ))}
        </div>

        {/* Projects list */}
        {loading ? (
          <div className="text-center text-gray-500 py-20">Loading projects...</div>
        ) : projects.length === 0 ? (
          <div className="text-center text-gray-500 py-20">No {filter} projects found</div>
        ) : (
          <div className="space-y-4">
            {projects.map(p => (
              <div key={p._id} style={{ background: '#111827', border: '1px solid #1f2937' }}
                   className="rounded-2xl p-6">

                <div className="flex items-start justify-between mb-4">
                  <div className="flex-1">
                    <h3 className="font-bold text-lg mb-1">{p.title}</h3>
                    <div className="flex gap-3 text-xs text-gray-400">
                      <span>By {p.innovator?.name}</span>
                      <span>·</span>
                      <span>{p.category}</span>
                      <span>·</span>
                      <span>Goal: ${p.fundingGoal?.toLocaleString()}</span>
                      <span>·</span>
                      <span>Team: {p.teamSize}</span>
                    </div>
                  </div>

                  <div className="flex items-center gap-3 ml-4">
                    <span style={{
                      color: p.status === 'approved' ? '#10b981' : p.status === 'rejected' ? '#ef4444' : '#f59e0b',
                      background: p.status === 'approved' ? '#10b98115' : p.status === 'rejected' ? '#ef444415' : '#f59e0b15',
                      border: `1px solid ${p.status === 'approved' ? '#10b98130' : p.status === 'rejected' ? '#ef444430' : '#f59e0b30'}`
                    }} className="px-3 py-1 rounded-full text-xs font-medium capitalize">
                      {p.status}
                    </span>

                    {/* Admin Delete button */}
                    {confirmDeleteId === p._id ? (
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-gray-400">Sure?</span>
                        <button
                          onClick={() => handleDelete(p._id)}
                          disabled={deletingId === p._id}
                          style={{ background: '#ef4444', color: 'white' }}
                          className="px-3 py-1 rounded-lg text-xs font-semibold hover:opacity-90 disabled:opacity-60 transition-all">
                          {deletingId === p._id ? 'Deleting...' : 'Yes'}
                        </button>
                        <button
                          onClick={() => setConfirmDeleteId(null)}
                          style={{ background: '#1f2937', color: '#9ca3af' }}
                          className="px-3 py-1 rounded-lg text-xs font-semibold transition-all">
                          No
                        </button>
                      </div>
                    ) : (
                      <button
                        onClick={() => setConfirmDeleteId(p._id)}
                        style={{ border: '1px solid #374151', color: '#ef4444' }}
                        className="px-3 py-1 rounded-lg text-xs font-semibold hover:border-red-500 hover:bg-red-500 hover:bg-opacity-10 transition-all">
                        🗑 Delete
                      </button>
                    )}
                  </div>
                </div>

                <p className="text-gray-400 text-sm mb-4 leading-relaxed line-clamp-2">{p.description}</p>

                {/* AI Scores */}
                {p.aiEvaluation?.feasibilityScore !== null ? (
                  <div style={{ background: '#0a0d1a', border: '1px solid rgba(0,212,170,0.2)' }}
                       className="rounded-xl p-4 mb-4">
                    <p style={{ color: '#00d4aa' }} className="text-xs font-bold uppercase tracking-wider mb-3">
                      ✦ Gemini AI Evaluation
                    </p>
                    <div className="grid grid-cols-2 gap-3 mb-3">
                      <div>
                        <div className="text-gray-400 text-xs mb-1">Feasibility Score</div>
                        <ScoreBar score={p.aiEvaluation.feasibilityScore} />
                      </div>
                      <div>
                        <div className="text-gray-400 text-xs mb-1">Success Probability</div>
                        <ScoreBar score={p.aiEvaluation.successProbability} />
                      </div>
                    </div>
                    <p className="text-gray-400 text-xs leading-relaxed">{p.aiEvaluation.explanation}</p>
                  </div>
                ) : (
                  <div className="text-gray-500 text-sm mb-4">⏳ AI evaluation pending...</div>
                )}

                {/* Approve / Reject actions */}
                {p.status === 'pending' && (
                  <div>
                    {actionTarget === p._id ? (
                      <div className="flex gap-3 items-center">
                        <input value={actionNote} onChange={e => setActionNote(e.target.value)}
                          style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
                          className="flex-1 px-3 py-2 rounded-lg text-sm"
                          placeholder="Admin note (optional)..." />
                        <button onClick={() => handleDecision(p._id, 'approve')}
                          style={{ background: '#10b981', color: 'white' }}
                          className="px-4 py-2 rounded-lg text-sm font-medium">
                          ✓ Approve
                        </button>
                        <button onClick={() => handleDecision(p._id, 'reject')}
                          style={{ background: '#ef4444', color: 'white' }}
                          className="px-4 py-2 rounded-lg text-sm font-medium">
                          ✗ Reject
                        </button>
                        <button onClick={() => { setActionTarget(null); setActionNote(''); }}
                          className="text-gray-400 text-sm">Cancel</button>
                      </div>
                    ) : (
                      <button onClick={() => setActionTarget(p._id)}
                        style={{ border: '1px solid #374151', color: '#9ca3af' }}
                        className="px-4 py-2 rounded-lg text-sm hover:border-teal-500 hover:text-white transition-all">
                        Review & Decide
                      </button>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
